module JK_latch (
    input wire obf_J,
    input wire K,
    input wire clk,
    output reg Q
);
    always @(posedge clk) begin
        if (obf_J && K) 
            Q <= ~Q;      // Toggle
        else if (obf_J) 
            Q <= 1'b1;    // Set
        else if (K) 
            Q <= 1'b0;    // Reset
        // If both obf_J and K are low, Q remains unchanged
    end
endmodule
